func getBankBadgeClass(bank string) string {
	b := strings.ToLower(bank)
	if strings.Contains(b, "bca") {
		return "badge-blue"
	} else if strings.Contains(b, "blu") {
		return "badge-purple"
	}
	return "badge-default"
}

